{
  "name": "Ikigai Compass",
  "description": "A self-discovery journey where an AI guide leads you through a series of profound questions to help you uncover your life's purpose and future direction.",
  "requestFramePermissions": ["microphone"]
}

export interface Message {
  id: string;
  role: 'user' | 'assistant';
  content: string;
  timestamp: number;
}

export interface DiscoveryResult {
  title: string;
  summary: string;
  keyInsights: string[];
  suggestedPaths: string[];
  motto: string;
}

export type AppState = 'landing' | 'chatting' | 'analyzing' | 'result';

import { GoogleGenAI, Type } from "@google/genai";
import { Message, DiscoveryResult } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

const SYSTEM_INSTRUCTION = `You are a wise, empathetic, and philosophical Life Discovery Guide. 
Your goal is to help the user uncover their life purpose (Ikigai) or career direction through a Socratic dialogue.

GUIDELINES:
1. YOU ARE THE QUESTIONER. This is a reverse-interview.
2. Ask exactly ONE profound, open-ended question at a time.
3. Listen deeply to their answers. Use their previous response to inform your next question.
4. Keep the tone calm, insightful, and supportive.
5. Focus on four areas: What they love, what they are good at, what the world needs, and what they can be paid for.
6. Do not give advice or conclusions until the final synthesis phase.
7. After 8-12 questions, if you have enough information, you should signal completion.

The user's first input is just "START". When you see this, introduce yourself briefly and ask the first foundational question.`;

export const getNextQuestion = async (history: Message[]): Promise<string> => {
  const contents = history.map(m => ({
    role: m.role === 'assistant' ? 'model' : 'user',
    parts: [{ text: m.content }]
  }));

  const response = await ai.models.generateContent({
    model: 'gemini-3-pro-preview',
    contents: contents as any,
    config: {
      systemInstruction: SYSTEM_INSTRUCTION,
      temperature: 0.8,
    },
  });

  return response.text || "Could you tell me more about that?";
};

export const generateFinalAnalysis = async (history: Message[]): Promise<DiscoveryResult> => {
  const conversation = history.map(m => `${m.role.toUpperCase()}: ${m.content}`).join('\n');

  const prompt = `Based on the following deep conversation, synthesize a "Life Purpose Map" for the user.

  CONVERSATION:
  ${conversation}

  Provide a JSON object representing the analysis.`;

  const response = await ai.models.generateContent({
    model: 'gemini-3-pro-preview',
    contents: [{ parts: [{ text: prompt }] }],
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          title: { type: Type.STRING, description: "A poetic title for their life path" },
          summary: { type: Type.STRING, description: "A 2-3 sentence overview of their core essence" },
          keyInsights: { 
            type: Type.ARRAY, 
            items: { type: Type.STRING },
            description: "3-5 deep insights about their strengths/values revealed" 
          },
          suggestedPaths: { 
            type: Type.ARRAY, 
            items: { type: Type.STRING },
            description: "3 actionable future directions or career paths" 
          },
          motto: { type: Type.STRING, description: "A short, powerful personal mantra" }
        },
        required: ["title", "summary", "keyInsights", "suggestedPaths", "motto"]
      }
    }
  });

  return JSON.parse(response.text || "{}");
};

import React from 'react';
import { Message } from '../types';

interface ChatBubbleProps {
  message: Message;
}

export const ChatBubble: React.FC<ChatBubbleProps> = ({ message }) => {
  const isAssistant = message.role === 'assistant';

  return (
    <div className={`flex w-full mb-6 ${isAssistant ? 'justify-start' : 'justify-end'}`}>
      <div 
        className={`max-w-[85%] md:max-w-[70%] px-6 py-4 rounded-2xl shadow-sm transition-all duration-300 ${
          isAssistant 
            ? 'bg-white text-gray-800 border border-gray-100 rounded-tl-none' 
            : 'bg-indigo-600 text-white rounded-tr-none'
        }`}
      >
        <p className={`text-lg leading-relaxed ${isAssistant ? 'font-serif italic' : 'font-sans'}`}>
          {message.content}
        </p>
        <span className={`text-[10px] mt-2 block opacity-50 ${isAssistant ? 'text-gray-500' : 'text-indigo-100'}`}>
          {new Date(message.timestamp).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })}
        </span>
      </div>
    </div>
  );
};

import React from 'react';

interface ProgressBarProps {
  current: number;
  total: number;
}

export const ProgressBar: React.FC<ProgressBarProps> = ({ current, total }) => {
  const percentage = Math.min((current / total) * 100, 100);

  return (
    <div className="w-full bg-gray-100 h-1.5 rounded-full overflow-hidden">
      <div 
        className="bg-indigo-500 h-full transition-all duration-700 ease-out"
        style={{ width: `${percentage}%` }}
      />
    </div>
  );
};

import React, { useState, useEffect, useRef } from 'react';
import { Message, DiscoveryResult, AppState } from './types';
import { getNextQuestion, generateFinalAnalysis } from './services/geminiService';
import { ChatBubble } from './components/ChatBubble';
import { ProgressBar } from './components/ProgressBar';
import { 
  Compass, 
  Send, 
  RefreshCw, 
  Sparkles, 
  ArrowRight, 
  ChevronRight, 
  Lightbulb, 
  Navigation,
  Quote
} from 'lucide-react';

const TOTAL_QUESTIONS = 10;

const App: React.FC = () => {
  const [state, setState] = useState<AppState>('landing');
  const [messages, setMessages] = useState<Message[]>([]);
  const [input, setInput] = useState('');
  const [isLoading, setIsLoading] = useState(false);
  const [result, setResult] = useState<DiscoveryResult | null>(null);
  const [questionCount, setQuestionCount] = useState(0);

  const scrollRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    if (scrollRef.current) {
      scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
    }
  }, [messages, isLoading]);

  const startJourney = async () => {
    setState('chatting');
    setIsLoading(true);
    const initialMessage: Message = { id: 'start', role: 'user', content: 'START', timestamp: Date.now() };
    const firstQuestion = await getNextQuestion([initialMessage]);
    setMessages([{ 
      id: Date.now().toString(), 
      role: 'assistant', 
      content: firstQuestion, 
      timestamp: Date.now() 
    }]);
    setQuestionCount(1);
    setIsLoading(false);
  };

  const handleSend = async () => {
    if (!input.trim() || isLoading) return;

    const userMessage: Message = {
      id: Date.now().toString(),
      role: 'user',
      content: input,
      timestamp: Date.now()
    };

    setMessages(prev => [...prev, userMessage]);
    setInput('');
    setIsLoading(true);

    if (questionCount >= TOTAL_QUESTIONS) {
      setState('analyzing');
      const finalResult = await generateFinalAnalysis([...messages, userMessage]);
      setResult(finalResult);
      setState('result');
      setIsLoading(false);
      return;
    }

    try {
      const nextQ = await getNextQuestion([...messages, userMessage]);
      const assistantMessage: Message = {
        id: (Date.now() + 1).toString(),
        role: 'assistant',
        content: nextQ,
        timestamp: Date.now()
      };
      setMessages(prev => [...prev, assistantMessage]);
      setQuestionCount(prev => prev + 1);
    } catch (error) {
      console.error(error);
    } finally {
      setIsLoading(false);
    }
  };

  const reset = () => {
    setState('landing');
    setMessages([]);
    setQuestionCount(0);
    setResult(null);
    setInput('');
  };

  if (state === 'landing') {
    return (
      <div className="min-h-screen flex flex-col items-center justify-center p-6 bg-gradient-to-br from-slate-50 to-indigo-50">
        <div className="max-w-2xl w-full text-center space-y-12">
          <div className="flex justify-center">
            <div className="w-24 h-24 bg-white rounded-3xl shadow-xl flex items-center justify-center animate-bounce duration-1000">
              <Compass size={48} className="text-indigo-600" />
            </div>
          </div>
          <div className="space-y-4">
            <h1 className="text-5xl font-serif font-bold text-slate-900 tracking-tight">Ikigai Compass</h1>
            <p className="text-xl text-slate-600 leading-relaxed max-w-lg mx-auto">
              Embark on a guided introspective journey. Our AI guide will ask you profound questions to map your life's true north.
            </p>
          </div>
          <button 
            onClick={startJourney}
            className="group relative px-12 py-5 bg-indigo-600 text-white rounded-2xl font-semibold text-lg hover:bg-indigo-700 transition-all shadow-xl hover:shadow-indigo-200/50 flex items-center gap-3 mx-auto"
          >
            Begin Your Discovery
            <ArrowRight className="group-hover:translate-x-1 transition-transform" />
          </button>
          <p className="text-sm text-slate-400">10 deep questions. One clear path.</p>
        </div>
      </div>
    );
  }

  if (state === 'analyzing') {
    return (
      <div className="min-h-screen flex flex-col items-center justify-center p-6 bg-slate-50">
        <div className="text-center space-y-8 max-w-md">
          <div className="relative">
            <div className="absolute inset-0 bg-indigo-200 rounded-full blur-2xl opacity-30 animate-pulse"></div>
            <Sparkles size={80} className="text-indigo-500 mx-auto relative animate-spin-slow" />
          </div>
          <h2 className="text-3xl font-serif font-bold text-slate-900">Synthesizing Your Journey...</h2>
          <p className="text-slate-600">Our guide is weaving your insights into a map for your future. Please wait a moment.</p>
          <div className="w-full bg-slate-200 h-1.5 rounded-full overflow-hidden">
            <div className="bg-indigo-500 h-full w-full animate-[loading_3s_ease-in-out_infinite]"></div>
          </div>
        </div>
        <style>{`
          @keyframes loading {
            0% { transform: translateX(-100%); }
            100% { transform: translateX(100%); }
          }
          .animate-spin-slow {
            animation: spin 8s linear infinite;
          }
          @keyframes spin {
            from { transform: rotate(0deg); }
            to { transform: rotate(360deg); }
          }
        `}</style>
      </div>
    );
  }

  if (state === 'result' && result) {
    return (
      <div className="min-h-screen bg-slate-50 py-12 px-4 md:px-8">
        <div className="max-w-4xl mx-auto space-y-12">
          <div className="text-center space-y-4">
            <div className="inline-flex items-center gap-2 px-4 py-2 bg-indigo-100 text-indigo-700 rounded-full text-sm font-medium">
              <Sparkles size={16} /> Your Purpose Synthesis
            </div>
            <h1 className="text-5xl font-serif font-bold text-slate-900">{result.title}</h1>
          </div>

          <div className="grid md:grid-cols-3 gap-8">
            <div className="md:col-span-2 space-y-8">
              <section className="bg-white p-8 rounded-3xl shadow-sm border border-slate-100 space-y-4">
                <h3 className="text-xl font-bold flex items-center gap-2 text-slate-800">
                  <Lightbulb className="text-amber-500" /> Core Essence
                </h3>
                <p className="text-lg text-slate-600 leading-relaxed font-serif">
                  {result.summary}
                </p>
              </section>

              <div className="grid sm:grid-cols-2 gap-6">
                <section className="bg-white p-8 rounded-3xl shadow-sm border border-slate-100 space-y-6">
                  <h3 className="text-xl font-bold flex items-center gap-2 text-slate-800">
                    <Quote className="text-indigo-400" /> Key Insights
                  </h3>
                  <ul className="space-y-4">
                    {result.keyInsights.map((insight, i) => (
                      <li key={i} className="flex gap-3 text-slate-600">
                        <ChevronRight className="flex-shrink-0 text-indigo-500 mt-1" size={18} />
                        <span>{insight}</span>
                      </li>
                    ))}
                  </ul>
                </section>

                <section className="bg-white p-8 rounded-3xl shadow-sm border border-slate-100 space-y-6">
                  <h3 className="text-xl font-bold flex items-center gap-2 text-slate-800">
                    <Navigation className="text-teal-500" /> Suggested Paths
                  </h3>
                  <div className="space-y-3">
                    {result.suggestedPaths.map((path, i) => (
                      <div key={i} className="p-4 bg-slate-50 rounded-xl border border-slate-100 text-slate-700 font-medium">
                        {path}
                      </div>
                    ))}
                  </div>
                </section>
              </div>
            </div>

            <div className="space-y-8">
              <div className="bg-indigo-600 text-white p-10 rounded-3xl shadow-xl space-y-6 flex flex-col items-center justify-center text-center">
                <p className="text-sm uppercase tracking-widest opacity-70">Your Personal Mantra</p>
                <h2 className="text-3xl font-serif italic font-bold">"{result.motto}"</h2>
              </div>

              <button 
                onClick={reset}
                className="w-full flex items-center justify-center gap-2 py-4 bg-white text-slate-700 font-semibold rounded-2xl border-2 border-slate-200 hover:bg-slate-50 transition-colors shadow-sm"
              >
                <RefreshCw size={20} /> Start New Journey
              </button>
            </div>
          </div>
        </div>
      </div>
    );
  }

  return (
    <div className="flex flex-col h-screen bg-slate-50">
      {/* Header */}
      <header className="glass sticky top-0 z-10 px-6 py-4 flex items-center justify-between border-b">
        <div className="flex items-center gap-3">
          <div className="p-2 bg-indigo-600 rounded-lg">
            <Compass size={20} className="text-white" />
          </div>
          <div>
            <h1 className="font-serif font-bold text-slate-900 leading-tight">Ikigai Compass</h1>
            <p className="text-xs text-slate-500">Journey through the self</p>
          </div>
        </div>
        <div className="flex items-center gap-4">
          <div className="hidden md:block w-48">
            <ProgressBar current={questionCount} total={TOTAL_QUESTIONS} />
          </div>
          <span className="text-xs font-mono font-bold text-indigo-600 bg-indigo-50 px-2 py-1 rounded">
            {questionCount}/{TOTAL_QUESTIONS}
          </span>
          <button 
            onClick={() => { if(confirm('Exit current journey?')) reset() }}
            className="p-2 text-slate-400 hover:text-red-500 transition-colors"
          >
            <RefreshCw size={18} />
          </button>
        </div>
      </header>

      {/* Chat Area */}
      <main 
        ref={scrollRef}
        className="flex-1 overflow-y-auto px-4 md:px-0 py-8 scroll-smooth"
      >
        <div className="max-w-3xl mx-auto flex flex-col gap-2">
          {messages.map((m) => (
            <ChatBubble key={m.id} message={m} />
          ))}
          {isLoading && (
            <div className="flex justify-start mb-6">
              <div className="bg-white border border-gray-100 rounded-2xl rounded-tl-none px-6 py-4 shadow-sm">
                <div className="flex gap-1">
                  <div className="w-1.5 h-1.5 bg-indigo-400 rounded-full animate-bounce"></div>
                  <div className="w-1.5 h-1.5 bg-indigo-400 rounded-full animate-bounce delay-150"></div>
                  <div className="w-1.5 h-1.5 bg-indigo-400 rounded-full animate-bounce delay-300"></div>
                </div>
              </div>
            </div>
          )}
        </div>
      </main>

      {/* Input Area */}
      <footer className="p-4 md:p-8 glass-top">
        <div className="max-w-3xl mx-auto relative">
          <textarea
            value={input}
            onChange={(e) => setInput(e.target.value)}
            onKeyDown={(e) => {
              if (e.key === 'Enter' && !e.shiftKey) {
                e.preventDefault();
                handleSend();
              }
            }}
            placeholder="Share your thoughts..."
            rows={2}
            className="w-full pl-6 pr-16 py-4 bg-white border border-slate-200 rounded-2xl shadow-lg focus:outline-none focus:ring-2 focus:ring-indigo-500/20 focus:border-indigo-500 transition-all resize-none text-lg"
          />
          <button 
            onClick={handleSend}
            disabled={!input.trim() || isLoading}
            className={`absolute right-3 bottom-3 p-3 rounded-xl transition-all ${
              !input.trim() || isLoading 
                ? 'bg-slate-100 text-slate-400' 
                : 'bg-indigo-600 text-white shadow-lg shadow-indigo-200 hover:bg-indigo-700'
            }`}
          >
            <Send size={24} />
          </button>
        </div>
        <p className="text-center mt-4 text-xs text-slate-400">
          Be as honest and detailed as possible. The more you give, the more you discover.
        </p>
      </footer>
    </div>
  );
};

export default App;

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

import { GoogleGenAI, Type } from "@google/genai";
import { Message, DiscoveryResult } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

const SYSTEM_INSTRUCTION = `You are a wise, empathetic, and philosophical Life Discovery Guide. 
Your goal is to help the user uncover their life purpose (Ikigai) or career direction through a Socratic dialogue.

CRITICAL INSTRUCTION: 
1. ALWAYS respond in a bilingual format: Chinese followed by English. 
   Example: "你在这个世界上最热爱的事情是什么？/ What is the thing you love most in this world?"
2. YOU ARE THE QUESTIONER. This is a reverse-interview.
3. Ask exactly ONE profound, open-ended question at a time.
4. Listen deeply to their answers. Use their previous response to inform your next question.
5. Keep the tone calm, insightful, and supportive.
6. Focus on four areas: What they love, what they are good at, what the world needs, and what they can be paid for.
7. Do not give advice or conclusions until the final synthesis phase.
8. After 8-12 questions, if you have enough information, you should signal completion.

The user's first input is just "START". When you see this, introduce yourself briefly and ask the first foundational question in both Chinese and English.`;

export const getNextQuestion = async (history: Message[]): Promise<string> => {
  const contents = history.map(m => ({
    role: m.role === 'assistant' ? 'model' : 'user',
    parts: [{ text: m.content }]
  }));

  const response = await ai.models.generateContent({
    model: 'gemini-3-pro-preview',
    contents: contents as any,
    config: {
      systemInstruction: SYSTEM_INSTRUCTION,
      temperature: 0.8,
    },
  });

  return response.text || "Could you tell me more about that? / 你能多跟我说说吗？";
};

export const generateFinalAnalysis = async (history: Message[]): Promise<DiscoveryResult> => {
  const conversation = history.map(m => `${m.role.toUpperCase()}: ${m.content}`).join('\n');

  const prompt = `Based on the following deep conversation, synthesize a "Life Purpose Map" for the user.

  CONVERSATION:
  ${conversation}

  Provide a JSON object representing the analysis. 
  IMPORTANT: All string fields (title, summary, keyInsights, suggestedPaths, motto) MUST contain both Chinese and English translations in the format "中文内容 / English content".`;

  const response = await ai.models.generateContent({
    model: 'gemini-3-pro-preview',
    contents: [{ parts: [{ text: prompt }] }],
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          title: { type: Type.STRING, description: "A poetic title for their life path (Bilingual)" },
          summary: { type: Type.STRING, description: "A 2-3 sentence overview of their core essence (Bilingual)" },
          keyInsights: { 
            type: Type.ARRAY, 
            items: { type: Type.STRING },
            description: "3-5 deep insights about their strengths/values revealed (Bilingual)" 
          },
          suggestedPaths: { 
            type: Type.ARRAY, 
            items: { type: Type.STRING },
            description: "3 actionable future directions or career paths (Bilingual)" 
          },
          motto: { type: Type.STRING, description: "A short, powerful personal mantra (Bilingual)" }
        },
        required: ["title", "summary", "keyInsights", "suggestedPaths", "motto"]
      }
    }
  });

  return JSON.parse(response.text || "{}");
};

import React, { useState, useEffect, useRef } from 'react';
import { Message, DiscoveryResult, AppState } from './types';
import { getNextQuestion, generateFinalAnalysis } from './services/geminiService';
import { ChatBubble } from './components/ChatBubble';
import { ProgressBar } from './components/ProgressBar';
import { 
  Compass, 
  Send, 
  RefreshCw, 
  Sparkles, 
  ArrowRight, 
  ChevronRight, 
  Lightbulb, 
  Navigation,
  Quote
} from 'lucide-react';

const TOTAL_QUESTIONS = 10;

const App: React.FC = () => {
  const [state, setState] = useState<AppState>('landing');
  const [messages, setMessages] = useState<Message[]>([]);
  const [input, setInput] = useState('');
  const [isLoading, setIsLoading] = useState(false);
  const [result, setResult] = useState<DiscoveryResult | null>(null);
  const [questionCount, setQuestionCount] = useState(0);

  const scrollRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    if (scrollRef.current) {
      scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
    }
  }, [messages, isLoading]);

  const startJourney = async () => {
    setState('chatting');
    setIsLoading(true);
    const initialMessage: Message = { id: 'start', role: 'user', content: 'START', timestamp: Date.now() };
    const firstQuestion = await getNextQuestion([initialMessage]);
    setMessages([{ 
      id: Date.now().toString(), 
      role: 'assistant', 
      content: firstQuestion, 
      timestamp: Date.now() 
    }]);
    setQuestionCount(1);
    setIsLoading(false);
  };

  const handleSend = async () => {
    if (!input.trim() || isLoading) return;

    const userMessage: Message = {
      id: Date.now().toString(),
      role: 'user',
      content: input,
      timestamp: Date.now()
    };

    setMessages(prev => [...prev, userMessage]);
    setInput('');
    setIsLoading(true);

    if (questionCount >= TOTAL_QUESTIONS) {
      setState('analyzing');
      try {
        const finalResult = await generateFinalAnalysis([...messages, userMessage]);
        setResult(finalResult);
        setState('result');
      } catch (e) {
        console.error("Analysis failed", e);
        setState('chatting'); // Fallback
      } finally {
        setIsLoading(false);
      }
      return;
    }

    try {
      const nextQ = await getNextQuestion([...messages, userMessage]);
      const assistantMessage: Message = {
        id: (Date.now() + 1).toString(),
        role: 'assistant',
        content: nextQ,
        timestamp: Date.now()
      };
      setMessages(prev => [...prev, assistantMessage]);
      setQuestionCount(prev => prev + 1);
    } catch (error) {
      console.error(error);
    } finally {
      setIsLoading(false);
    }
  };

  const reset = () => {
    setState('landing');
    setMessages([]);
    setQuestionCount(0);
    setResult(null);
    setInput('');
  };

  if (state === 'landing') {
    return (
      <div className="min-h-screen flex flex-col items-center justify-center p-6 bg-gradient-to-br from-slate-50 to-indigo-50">
        <div className="max-w-2xl w-full text-center space-y-12">
          <div className="flex justify-center">
            <div className="w-24 h-24 bg-white rounded-3xl shadow-xl flex items-center justify-center animate-bounce duration-1000">
              <Compass size={48} className="text-indigo-600" />
            </div>
          </div>
          <div className="space-y-4">
            <h1 className="text-5xl font-serif font-bold text-slate-900 tracking-tight">Ikigai Compass</h1>
            <h2 className="text-2xl font-serif text-indigo-600">人生意义指南针</h2>
            <p className="text-xl text-slate-600 leading-relaxed max-w-lg mx-auto">
              Embark on a guided introspective journey. Our AI guide will ask you profound questions to map your life's true north.
              <br/><span className="text-base text-slate-400">开启一段受引导的内省之旅。我们的AI助手将通过深刻的提问，绘制属于你的人生意向图。</span>
            </p>
          </div>
          <button 
            onClick={startJourney}
            className="group relative px-12 py-5 bg-indigo-600 text-white rounded-2xl font-semibold text-lg hover:bg-indigo-700 transition-all shadow-xl hover:shadow-indigo-200/50 flex items-center gap-3 mx-auto"
          >
