import { 
  Compass, 
  Send, 
  RefreshCw, 
  Sparkles, 
  ArrowRight, 
  ChevronRight, 
  Lightbulb, 
  Navigation,
  Quote,
  Languages
} from 'lucide-react';

const TOTAL_QUESTIONS = 10;

const i18n = {
  zh: {
    title: "Ikigai Compass",
    subtitle: "人生意义指南针",
