    landingDesc: "Embark on a guided introspective journey. Our AI guide will ask you profound questions to map your life's true north.",
    landingHint: "10 deep questions. One clear path.",
    beginBtn: "Begin Your Discovery",
    analyzingTitle: "Synthesizing Your Journey...",
    analyzingDesc: "Our guide is weaving your insights into a map for your future.",
    resultTitle: "Purpose Synthesis",
    coreEssence: "Core Essence",
    keyInsights: "Key Insights",
    suggestedPaths: "Suggested Paths",
    mantra: "Your Mantra",
    restart: "Start New Journey",
    inputPlaceholder: "Share your thoughts...",
    inputHint: "Be honest and detailed.",
    exitConfirm: "Exit current journey?",
    selfDiscovery: "Self-Discovery",
  }
};

const App: React.FC = () => {
  const [state, setState] = useState<AppState>('landing');
  const [lang, setLang] = useState<Language>('zh');
  const [messages, setMessages] = useState<Message[]>([]);
  const [input, setInput] = useState('');
  const [isLoading, setIsLoading] = useState(false);
  const [result, setResult] = useState<DiscoveryResult | null>(null);
  const [questionCount, setQuestionCount] = useState(0);

  const scrollRef = useRef<HTMLDivElement>(null);
  const t = i18n[lang];

  useEffect(() => {
    if (scrollRef.current) {
      scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
    }
  }, [messages, isLoading]);

  const toggleLanguage = () => {
    setLang(prev => prev === 'zh' ? 'en' : 'zh');
  };

  const startJourney = async () => {
    setState('chatting');
    setIsLoading(true);
    const initialMessage: Message = { id: 'start', role: 'user', content: 'START', timestamp: Date.now() };
    const firstQuestion = await getNextQuestion([initialMessage]);
    setMessages([{ 
      id: Date.now().toString(), 
      role: 'assistant', 
      content: firstQuestion, 
      timestamp: Date.now() 
    }]);
    setQuestionCount(1);
    setIsLoading(false);
  };

  const handleSend = async () => {
    if (!input.trim() || isLoading) return;

    const userMessage: Message = {
      id: Date.now().toString(),
      role: 'user',
      content: input,
      timestamp: Date.now()
    };

    setMessages(prev => [...prev, userMessage]);
    setInput('');
    setIsLoading(true);

    if (questionCount >= TOTAL_QUESTIONS) {
      setState('analyzing');
      try {
        const finalResult = await generateFinalAnalysis([...messages, userMessage]);
        setResult(finalResult);
        setState('result');
      } catch (e) {
        console.error("Analysis failed", e);
        setState('chatting');
      } finally {
        setIsLoading(false);
      }
      return;
    }

    try {
      const nextQ = await getNextQuestion([...messages, userMessage]);
      const assistantMessage: Message = {
        id: (Date.now() + 1).toString(),
        role: 'assistant',
        content: nextQ,
        timestamp: Date.now()
      };
      setMessages(prev => [...prev, assistantMessage]);
      setQuestionCount(prev => prev + 1);
    } catch (error) {
      console.error(error);
    } finally {
      setIsLoading(false);
    }
  };

  const reset = () => {
    setState('landing');
    setMessages([]);
    setQuestionCount(0);
    setResult(null);
    setInput('');
  };

  const parseBilingual = (text: string) => {
    const parts = text.split(' / ');
    if (parts.length < 2) return text;
    return lang === 'zh' ? parts[0] : parts[1];
  };

  if (state === 'landing') {
    return (
      <div className="min-h-screen flex flex-col items-center justify-center p-6 bg-gradient-to-br from-slate-50 to-indigo-50 relative">
        <button 
          onClick={toggleLanguage}
          className="absolute top-8 right-8 flex items-center gap-2 px-4 py-2 bg-white rounded-full shadow-sm hover:shadow-md transition-all text-sm font-medium text-slate-600"
        >
          <Languages size={18} />
          {lang === 'zh' ? 'English' : '中文'}
        </button>

        <div className="max-w-2xl w-full text-center space-y-12">
          <div className="flex justify-center">
            <div className="w-24 h-24 bg-white rounded-3xl shadow-xl flex items-center justify-center animate-bounce duration-1000">
              <Compass size={48} className="text-indigo-600" />
            </div>
          </div>
          <div className="space-y-4">
            <h1 className="text-5xl font-serif font-bold text-slate-900 tracking-tight">{t.title}</h1>
            <h2 className="text-2xl font-serif text-indigo-600">{t.subtitle}</h2>
            <p className="text-xl text-slate-600 leading-relaxed max-w-lg mx-auto">
              {t.landingDesc}
            </p>
          </div>
          <button 
            onClick={startJourney}
            className="group relative px-12 py-5 bg-indigo-600 text-white rounded-2xl font-semibold text-lg hover:bg-indigo-700 transition-all shadow-xl hover:shadow-indigo-200/50 flex items-center gap-3 mx-auto"
          >
            <span>{t.beginBtn}</span>
            <ArrowRight className="group-hover:translate-x-1 transition-transform" />
          </button>
          <p className="text-sm text-slate-400">{t.landingHint}</p>
        </div>
      </div>
    );
  }

  if (state === 'analyzing') {
    return (
      <div className="min-h-screen flex flex-col items-center justify-center p-6 bg-slate-50">
        <div className="text-center space-y-8 max-w-md">
          <div className="relative">
            <div className="absolute inset-0 bg-indigo-200 rounded-full blur-2xl opacity-30 animate-pulse"></div>
            <Sparkles size={80} className="text-indigo-500 mx-auto relative animate-spin-slow" />
          </div>
          <div className="space-y-2">
            <h2 className="text-3xl font-serif font-bold text-slate-900">{t.analyzingTitle}</h2>
          </div>
          <p className="text-slate-600 italic font-serif">"{t.analyzingDesc}"</p>
          <div className="w-full bg-slate-200 h-1.5 rounded-full overflow-hidden">
            <div className="bg-indigo-500 h-full w-full animate-[loading_3s_ease-in-out_infinite]"></div>
          </div>
        </div>
        <style>{`
          @keyframes loading {
            0% { transform: translateX(-100%); }
            100% { transform: translateX(100%); }
          }
          .animate-spin-slow {
            animation: spin 8s linear infinite;
          }
          @keyframes spin {
            from { transform: rotate(0deg); }
            to { transform: rotate(360deg); }
          }
        `}</style>
      </div>
    );
  }

  if (state === 'result' && result) {
    return (
      <div className="min-h-screen bg-slate-50 py-12 px-4 md:px-8 relative">
        <button 
          onClick={toggleLanguage}
          className="fixed top-8 right-8 z-20 flex items-center gap-2 px-4 py-2 bg-white rounded-full shadow-md hover:shadow-lg transition-all text-sm font-medium text-slate-600"
        >
          <Languages size={18} />
          {lang === 'zh' ? 'English' : '中文'}
        </button>

        <div className="max-w-4xl mx-auto space-y-12">
          <div className="text-center space-y-4">
            <div className="inline-flex items-center gap-2 px-4 py-2 bg-indigo-100 text-indigo-700 rounded-full text-sm font-medium">
              <Sparkles size={16} /> {t.resultTitle}
            </div>
            <h1 className="text-4xl md:text-5xl font-serif font-bold text-slate-900">
              {parseBilingual(result.title)}
            </h1>
          </div>

          <div className="grid md:grid-cols-3 gap-8">
            <div className="md:col-span-2 space-y-8">
              <section className="bg-white p-8 rounded-3xl shadow-sm border border-slate-100 space-y-4">
                <h3 className="text-xl font-bold flex items-center gap-2 text-slate-800">
                  <Lightbulb className="text-amber-500" /> {t.coreEssence}
                </h3>
                <p className="text-lg text-slate-600 leading-relaxed font-serif">
                  {parseBilingual(result.summary)}
                </p>
              </section>

              <div className="grid sm:grid-cols-2 gap-6">
                <section className="bg-white p-8 rounded-3xl shadow-sm border border-slate-100 space-y-6">
                  <h3 className="text-xl font-bold flex items-center gap-2 text-slate-800">
                    <Quote className="text-indigo-400" /> {t.keyInsights}
                  </h3>
                  <ul className="space-y-4">
                    {result.keyInsights.map((insight, i) => (
                      <li key={i} className="flex gap-3 text-slate-600 text-sm md:text-base">
                        <ChevronRight className="flex-shrink-0 text-indigo-500 mt-1" size={18} />
                        <span>{parseBilingual(insight)}</span>
                      </li>
                    ))}
                  </ul>
                </section>

                <section className="bg-white p-8 rounded-3xl shadow-sm border border-slate-100 space-y-6">
                  <h3 className="text-xl font-bold flex items-center gap-2 text-slate-800">
                    <Navigation className="text-teal-500" /> {t.suggestedPaths}
                  </h3>
                  <div className="space-y-3">
                    {result.suggestedPaths.map((path, i) => (
                      <div key={i} className="p-4 bg-slate-50 rounded-xl border border-slate-100 text-slate-700 font-medium text-sm">
                        {parseBilingual(path)}
                      </div>
                    ))}
                  </div>
                </section>
              </div>
            </div>

            <div className="space-y-8">
              <div className="bg-indigo-600 text-white p-10 rounded-3xl shadow-xl space-y-6 flex flex-col items-center justify-center text-center min-h-[250px]">
                <p className="text-sm uppercase tracking-widest opacity-70">{t.mantra}</p>
                <h2 className="text-2xl md:text-3xl font-serif italic font-bold">"{parseBilingual(result.motto)}"</h2>
              </div>

              <button 
                onClick={reset}
                className="w-full flex items-center justify-center gap-2 py-4 bg-white text-slate-700 font-semibold rounded-2xl border-2 border-slate-200 hover:bg-slate-50 transition-colors shadow-sm"
              >
                <RefreshCw size={20} /> {t.restart}
              </button>
            </div>
          </div>
        </div>
      </div>
    );
  }

  return (
    <div className="flex flex-col h-screen bg-slate-50">
      {/* Header */}
      <header className="glass sticky top-0 z-10 px-6 py-4 flex items-center justify-between border-b">
        <div className="flex items-center gap-3">
          <div className="p-2 bg-indigo-600 rounded-lg">
            <Compass size={20} className="text-white" />
          </div>
          <div>
            <h1 className="font-serif font-bold text-slate-900 leading-tight">{t.title}</h1>
            <p className="text-[10px] md:text-xs text-slate-500">{t.selfDiscovery}</p>
          </div>
        </div>
        <div className="flex items-center gap-2 md:gap-4">
          <button 
            onClick={toggleLanguage}
            className="p-2 text-slate-400 hover:text-indigo-600 transition-colors flex items-center gap-1"
            title="Switch Language"
          >
            <Languages size={18} />
            <span className="hidden sm:inline text-xs font-bold uppercase">{lang}</span>
          </button>
          <div className="hidden md:block w-48">
            <ProgressBar current={questionCount} total={TOTAL_QUESTIONS} />
          </div>
          <span className="text-[10px] md:text-xs font-mono font-bold text-indigo-600 bg-indigo-50 px-2 py-1 rounded">
            {questionCount}/{TOTAL_QUESTIONS}
          </span>
          <button 
            onClick={() => { if(confirm(t.exitConfirm)) reset() }}
            className="p-2 text-slate-400 hover:text-red-500 transition-colors"
          >
            <RefreshCw size={18} />
          </button>
        </div>
      </header>

      {/* Chat Area */}
      <main 
        ref={scrollRef}
