          >
            <Send size={24} />
          </button>
        </div>
        <p className="text-center mt-4 text-[10px] md:text-xs text-slate-400">
          {t.inputHint}
        </p>
      </footer>
    </div>
  );
};

export default App;

import { GoogleGenAI, Type } from "@google/genai";
import { Message, DiscoveryResult } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

const SYSTEM_INSTRUCTION = `You are a wise, empathetic, and philosophical Life Discovery Guide. 
Your goal is to help the user uncover their life purpose (Ikigai) or career direction through a Socratic dialogue.

CRITICAL INSTRUCTION: 
1. ALWAYS respond in a bilingual format: Chinese followed by English, separated by " / ".
   Example: "你认为什么样的工作最有价值？ / What kind of work do you find most valuable?"
2. YOU ARE THE QUESTIONER. This is a reverse-interview.
3. Ask exactly ONE profound, open-ended question at a time.
4. Listen deeply to their answers. Use their previous response to inform your next question.
5. Focus on four areas: What they love, what they are good at, what the world needs, and what they can be paid for.
6. After 8-12 questions, if you have enough information, signal that the session is concluding.

The user's first input is just "START". Introduce yourself and ask the first foundational question in both Chinese and English using the " / " separator.`;

export const getNextQuestion = async (history: Message[]): Promise<string> => {
  const contents = history.map(m => ({
    role: m.role === 'assistant' ? 'model' : 'user',
    parts: [{ text: m.content }]
  }));

  const response = await ai.models.generateContent({
    model: 'gemini-3-pro-preview',
    contents: contents as any,
    config: {
      systemInstruction: SYSTEM_INSTRUCTION,
      temperature: 0.8,
    },
  });

  return response.text || "你能多跟我说说吗？ / Could you tell me more about that?";
};

export const generateFinalAnalysis = async (history: Message[]): Promise<DiscoveryResult> => {
  const conversation = history.map(m => `${m.role.toUpperCase()}: ${m.content}`).join('\n');

  const prompt = `Based on the following deep conversation, synthesize a "Life Purpose Map" for the user.

  CONVERSATION:
  ${conversation}

  Provide a JSON object representing the analysis. 
  IMPORTANT: All string fields (title, summary, keyInsights, suggestedPaths, motto) MUST contain both Chinese and English translations in the format "中文内容 / English content".`;

  const response = await ai.models.generateContent({
    model: 'gemini-3-pro-preview',
    contents: [{ parts: [{ text: prompt }] }],
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          title: { type: Type.STRING, description: "A poetic title for their life path (Bilingual with ' / ')" },
          summary: { type: Type.STRING, description: "A 2-3 sentence overview of their core essence (Bilingual with ' / ')" },
          keyInsights: { 
            type: Type.ARRAY, 
            items: { type: Type.STRING },
            description: "3-5 deep insights about their strengths/values revealed (Bilingual with ' / ')" 
          },
          suggestedPaths: { 
            type: Type.ARRAY, 
            items: { type: Type.STRING },
            description: "3 actionable future directions or career paths (Bilingual with ' / ')" 
          },
          motto: { type: Type.STRING, description: "A short, powerful personal mantra (Bilingual with ' / ')" }
        },
        required: ["title", "summary", "keyInsights", "suggestedPaths", "motto"]
      }
    }
  });

  return JSON.parse(response.text || "{}");
};

