import React from 'react';
import { Message, Language } from '../types';

interface ChatBubbleProps {
  message: Message;
  language: Language;
}

export const ChatBubble: React.FC<ChatBubbleProps> = ({ message, language }) => {
  const isAssistant = message.role === 'assistant';

  // 更加鲁棒的解析逻辑，适应各种可能的空格情况
  const getDisplayContent = (text: string) => {
    if (!isAssistant) return text;

    // 优先使用 [SEP] 分隔符，兼容旧的 / 分隔符
    let parts = text.split('[SEP]');
    if (parts.length < 2) {
      parts = text.split(' / ');
    }

    if (parts.length < 2) return text;

    const content = language === 'zh' ? parts[0] : parts[1];
    return content.trim();
  };

  return (
    <div className={`flex w-full mb-6 ${isAssistant ? 'justify-start' : 'justify-end'}`}>
      <div 
        className={`max-w-[85%] md:max-w-[70%] px-6 py-4 rounded-2xl shadow-sm transition-all duration-300 ${
          isAssistant 
            ? 'bg-white text-gray-800 border border-gray-100 rounded-tl-none' 
            : 'bg-indigo-600 text-white rounded-tr-none'
        }`}
      >
        <p className={`text-lg leading-relaxed ${isAssistant ? 'font-serif italic' : 'font-sans'}`}>
          {getDisplayContent(message.content)}
        </p>
        <span className={`text-[10px] mt-2 block opacity-50 ${isAssistant ? 'text-gray-500' : 'text-indigo-100'}`}>
          {new Date(message.timestamp).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })}
        </span>
      </div>
    </div>
  );
};

