const App: React.FC = () => {
  const [state, setState] = useState<AppState>('landing');
  const [lang, setLang] = useState<Language>('zh');
  const [messages, setMessages] = useState<Message[]>([]);
  const [input, setInput] = useState('');
  const [isLoading, setIsLoading] = useState(false);
  const [result, setResult] = useState<DiscoveryResult | null>(null);
  const [questionCount, setQuestionCount] = useState(0);

  const scrollRef = useRef<HTMLDivElement>(null);
  const t = i18n[lang];

  useEffect(() => {
    if (scrollRef.current) {
      scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
    }
  }, [messages, isLoading]);

  const toggleLanguage = () => {
    setLang(prev => prev === 'zh' ? 'en' : 'zh');
  };

  const startJourney = async () => {
    setState('chatting');
    setIsLoading(true);
    const initialMessage: Message = { id: 'start', role: 'user', content: 'START', timestamp: Date.now() };
    const firstQuestion = await getNextQuestion([initialMessage]);
    setMessages([{ 
      id: Date.now().toString(), 
      role: 'assistant', 
      content: firstQuestion, 
      timestamp: Date.now() 
    }]);
    setQuestionCount(1);
    setIsLoading(false);
  };

  const handleSend = async () => {
    if (!input.trim() || isLoading) return;

    const userMessage: Message = {
      id: Date.now().toString(),
      role: 'user',
      content: input,
      timestamp: Date.now()
    };

    setMessages(prev => [...prev, userMessage]);
    setInput('');
    setIsLoading(true);

    if (questionCount >= TOTAL_QUESTIONS) {
      setState('analyzing');
      try {
        const finalResult = await generateFinalAnalysis([...messages, userMessage]);
        setResult(finalResult);
        setState('result');
      } catch (e) {
        console.error("Analysis failed", e);
        setState('chatting');
      } finally {
        setIsLoading(false);
      }
      return;
    }

    try {
      const nextQ = await getNextQuestion([...messages, userMessage]);
      const assistantMessage: Message = {
        id: (Date.now() + 1).toString(),
        role: 'assistant',
        content: nextQ,
        timestamp: Date.now()
      };
      setMessages(prev => [...prev, assistantMessage]);
      setQuestionCount(prev => prev + 1);
    } catch (error) {
      console.error(error);
    } finally {
      setIsLoading(false);
    }
  };

  const reset = () => {
    setState('landing');
    setMessages([]);
    setQuestionCount(0);
    setResult(null);
    setInput('');
  };

  const parseBilingual = (text: string) => {
    let parts = text.split('[SEP]');
    if (parts.length < 2) {
      parts = text.split(' / ');
    }
    if (parts.length < 2) return text;
    return (lang === 'zh' ? parts[0] : parts[1]).trim();
  };

  if (state === 'landing') {
    return (
      <div className="min-h-screen flex flex-col items-center justify-center p-6 bg-gradient-to-br from-slate-50 to-indigo-50 relative">
