                  <ul className="space-y-4">
                    {result.keyInsights.map((insight, i) => (
                      <li key={i} className="flex gap-3 text-slate-600 text-sm md:text-base">
                        <ChevronRight className="flex-shrink-0 text-indigo-500 mt-1" size={18} />
                        <span>{parseBilingual(insight)}</span>
                      </li>
                    ))}
                  </ul>
                </section>

                <section className="bg-white p-8 rounded-3xl shadow-sm border border-slate-100 space-y-6">
                  <h3 className="text-xl font-bold flex items-center gap-2 text-slate-800">
                    <Navigation className="text-teal-500" /> {t.suggestedPaths}
                  </h3>
                  <div className="space-y-3">
                    {result.suggestedPaths.map((path, i) => (
                      <div key={i} className="p-4 bg-slate-50 rounded-xl border border-slate-100 text-slate-700 font-medium text-sm">
                        {parseBilingual(path)}
                      </div>
                    ))}
                  </div>
                </section>
              </div>
            </div>

            <div className="space-y-8">
              <div className="bg-indigo-600 text-white p-10 rounded-3xl shadow-xl space-y-6 flex flex-col items-center justify-center text-center min-h-[250px]">
                <p className="text-sm uppercase tracking-widest opacity-70">{t.mantra}</p>
                <h2 className="text-2xl md:text-3xl font-serif italic font-bold">"{parseBilingual(result.motto)}"</h2>
              </div>

              <button 
                onClick={reset}
                className="w-full flex items-center justify-center gap-2 py-4 bg-white text-slate-700 font-semibold rounded-2xl border-2 border-slate-200 hover:bg-slate-50 transition-colors shadow-sm"
              >
                <RefreshCw size={20} /> {t.restart}
              </button>
            </div>
          </div>
        </div>
      </div>
    );
  }

  return (
    <div className="flex flex-col h-screen bg-slate-50">
      {/* Header */}
      <header className="glass sticky top-0 z-10 px-6 py-4 flex items-center justify-between border-b">
        <div className="flex items-center gap-3">
          <div className="p-2 bg-indigo-600 rounded-lg">
            <Compass size={20} className="text-white" />
          </div>
          <div>
            <h1 className="font-serif font-bold text-slate-900 leading-tight">{t.title}</h1>
            <p className="text-[10px] md:text-xs text-slate-500">{t.selfDiscovery}</p>
          </div>
        </div>
        <div className="flex items-center gap-2 md:gap-4">
          <button 
            onClick={toggleLanguage}
            className="p-2 text-slate-400 hover:text-indigo-600 transition-colors flex items-center gap-1"
            title={t.langToggle}
          >
            <Languages size={18} />
            <span className="hidden sm:inline text-xs font-bold uppercase">{lang === 'zh' ? 'EN' : 'ZH'}</span>
          </button>
          <div className="hidden md:block w-48">
            <ProgressBar current={questionCount} total={TOTAL_QUESTIONS} />
          </div>
          <span className="text-[10px] md:text-xs font-mono font-bold text-indigo-600 bg-indigo-50 px-2 py-1 rounded">
            {questionCount}/{TOTAL_QUESTIONS}
          </span>
          <button 
            onClick={() => { if(confirm(t.exitConfirm)) reset() }}
            className="p-2 text-slate-400 hover:text-red-500 transition-colors"
          >
            <RefreshCw size={18} />
          </button>
        </div>
      </header>

      {/* Chat Area */}
      <main 
        ref={scrollRef}
        className="flex-1 overflow-y-auto px-4 md:px-0 py-8 scroll-smooth"
      >
        <div className="max-w-3xl mx-auto flex flex-col gap-2">
          {messages.map((m) => (
            <ChatBubble key={m.id} message={m} language={lang} />
          ))}
          {isLoading && (
            <div className="flex justify-start mb-6">
              <div className="bg-white border border-gray-100 rounded-2xl rounded-tl-none px-6 py-4 shadow-sm">
                <div className="flex gap-1">
                  <div className="w-1.5 h-1.5 bg-indigo-400 rounded-full animate-bounce"></div>
                  <div className="w-1.5 h-1.5 bg-indigo-400 rounded-full animate-bounce delay-150"></div>
                  <div className="w-1.5 h-1.5 bg-indigo-400 rounded-full animate-bounce delay-300"></div>
                </div>
              </div>
            </div>
          )}
        </div>
      </main>

      {/* Input Area */}
      <footer className="p-4 md:p-8 border-t bg-white">
        <div className="max-w-3xl mx-auto relative">
          <textarea
            value={input}
            onChange={(e) => setInput(e.target.value)}
            onKeyDown={(e) => {
              if (e.key === 'Enter' && !e.shiftKey) {
                e.preventDefault();
                handleSend();
              }
            }}
            placeholder={t.inputPlaceholder}
            rows={2}
            className="w-full pl-6 pr-16 py-4 bg-slate-50 border border-slate-200 rounded-2xl shadow-inner focus:outline-none focus:ring-2 focus:ring-indigo-500/20 focus:border-indigo-500 transition-all resize-none text-base md:text-lg"
          />
          <button 
            onClick={handleSend}
            disabled={!input.trim() || isLoading}
            className={`absolute right-3 bottom-3 p-3 rounded-xl transition-all ${
              !input.trim() || isLoading 
                ? 'bg-slate-100 text-slate-400' 
                : 'bg-indigo-600 text-white shadow-lg shadow-indigo-200 hover:bg-indigo-700'
            }`}
          >
            <Send size={24} />
          </button>
        </div>
        <p className="text-center mt-4 text-[10px] md:text-xs text-slate-400">
          {t.inputHint}
        </p>
      </footer>
    </div>
  );
};

export default App;

export type Language = 'zh' | 'en';
export type DiscoveryMode = 'LIFE_MEANING' | 'CAREER' | 'TALENT';

export interface Message {
  id: string;
  role: 'user' | 'assistant';
  content: string;
  timestamp: number;
}

export interface DiscoveryResult {
  title: string;
  summary: string;
  keyInsights: string[];
  suggestedPaths: string[];
  motto: string;
}

export type AppState = 'landing' | 'mode_select' | 'chatting' | 'analyzing' | 'result';

import { GoogleGenAI, Type } from "@google/genai";
import { Message, DiscoveryResult, DiscoveryMode } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

const getSystemInstruction = (mode: DiscoveryMode) => {
  let modeDesc = "";
  if (mode === 'LIFE_MEANING') {
    modeDesc = "侧重于深邃的哲学思辨和道德困境。借鉴电车难题、洞穴比喻等思想实验，探寻用户对真理、自由、痛苦、不朽等抽象概念的真实倾向。";
  } else if (mode === 'CAREER') {
    modeDesc = "侧重于职业选择和价值创造。探讨稳定性与风险、权力与自由、雇佣与创业的选择。通过假设性的商业或组织困境，分析用户的成就动机和协作模式。";
  } else {
    modeDesc = "侧重于内在天赋和心流体验。探讨好奇心的指向、对美感的捕捉、以及在体育、文学、音乐或技术中的感官偏好。通过具体的创作或探索场景，寻找用户的天职。";
  }

  return `你是一位专业的引导者。当前对话模式为：${modeDesc}

核心指令：
1. **强制双语格式**：每一条回复必须包含中文和英文两个版本，并使用分隔符 "[SEP]" 隔开。格式：[中文] [SEP] [English]。
2. **语言纯净度**：中文部分严禁混入英文单词；英文部分严禁混入中文。
3. **开篇即问**：用户发送 "START" 后，第一条消息必须直接抛出该模式下的第一个困境或问题，不要寒暄。
4. **决策权**：每次只提一个问题。当对话达到 5 轮以上且你认为已获得足够信息时，可以在回复中加入 [DONE] 标记以示结束。强制在 15 轮前结束。
5. **苏格拉底风格**：通过追问来解构用户的选择，不要急于给出建议。

警告：分隔符 [SEP] 是必须的。`;
};

export const getNextQuestion = async (history: Message[], mode: DiscoveryMode): Promise<string> => {
  const contents = history.map(m => ({
    role: m.role === 'assistant' ? 'model' : 'user',
    parts: [{ text: m.content }]
  }));

  const response = await ai.models.generateContent({
    model: 'gemini-3-pro-preview',
    contents: contents as any,
    config: {
      systemInstruction: getSystemInstruction(mode),
      temperature: 0.9,
    },
  });

  return response.text || "我们继续探讨吗？ [SEP] Shall we explore further?";
};

export const generateFinalAnalysis = async (history: Message[], mode: DiscoveryMode): Promise<DiscoveryResult> => {
  const conversation = history.map(m => `${m.role.toUpperCase()}: ${m.content}`).join('\n');

  const prompt = `基于以下关于“${mode}”模式的深度对话，为用户合成一份“人生探索图谱”。

  对话记录：
  ${conversation}

  请提供一个 JSON 对象。
  要求：所有字符串字段必须遵循“[中文] [SEP] [English]”格式。中文严禁出现英文。`;

  const response = await ai.models.generateContent({
    model: 'gemini-3-pro-preview',
    contents: [{ parts: [{ text: prompt }] }],
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          title: { type: Type.STRING, description: "路径标题 (Bilingual [SEP])" },
          summary: { type: Type.STRING, description: "深度综述 (Bilingual [SEP])" },
          keyInsights: { 
            type: Type.ARRAY, 
            items: { type: Type.STRING },
            description: "核心发现 (Bilingual [SEP])" 
          },
          suggestedPaths: { 
            type: Type.ARRAY, 
            items: { type: Type.STRING },
            description: "行动建议 (Bilingual [SEP])" 
          },
          motto: { type: Type.STRING, description: "灵魂信条 (Bilingual [SEP])" }
        },
        required: ["title", "summary", "keyInsights", "suggestedPaths", "motto"]
      }
    }
  });

  return JSON.parse(response.text || "{}");
};

import React, { useState, useEffect, useRef } from 'react';
import { Message, DiscoveryResult, AppState, Language, DiscoveryMode } from './types';
import { getNextQuestion, generateFinalAnalysis } from './services/geminiService';
import { ChatBubble } from './components/ChatBubble';
import { ProgressBar } from './components/ProgressBar';
import { 
  Compass, 
  Send, 
  RefreshCw, 
  Sparkles, 
  ArrowRight, 
  ChevronRight, 
  Lightbulb, 
  Navigation,
  Quote,
  Languages,
  Briefcase,
  Heart,
  ScrollText
} from 'lucide-react';

const MAX_QUESTIONS = 15;

const i18n = {
  zh: {
    title: "探索者指南针",
    subtitle: "从心出发，发现方向",
    landingDesc: "这不仅是一场对话，这是一次深度的自我剥离。请选择一个你当下最关心的探索领域。",
    beginBtn: "开启旅程",
    modeLife: "人生意义",
    modeLifeDesc: "深度哲学思辨",
    modeCareer: "职业方向",
    modeCareerDesc: "职场与创业抉择",
    modeTalent: "天赋爱好",
    modeTalentDesc: "潜能与兴趣挖掘",
    analyzingTitle: "正在编织你的图谱...",
    analyzingDesc: "AI 正在整合你的所有选择，生成独一无二的分析。",
    resultTitle: "探索报告",
    restart: "开始新探索",
    inputPlaceholder: "请深思熟虑后回答...",
    langToggle: "Switch to English",
    finishBtn: "完成对话，生成报告",
  },
  en: {
    title: "Explorer's Compass",
    subtitle: "Navigate Your Soul",
    landingDesc: "More than a chat, it's a deep self-uncovering. Select the path you wish to explore today.",
    beginBtn: "Start Journey",
    modeLife: "Meaning of Life",
    modeLifeDesc: "Philosophical Inquiry",
    modeCareer: "Career Path",
    modeCareerDesc: "Professional Growth",
    modeTalent: "Talent & Passion",
    modeTalentDesc: "Aptitude Discovery",
    analyzingTitle: "Synthesizing Your Map...",
    analyzingDesc: "AI is weaving your choices into a unique personal synthesis.",
    resultTitle: "Discovery Report",
    restart: "Start New Discovery",
    inputPlaceholder: "Answer with reflection...",
    langToggle: "切换至中文",
    finishBtn: "Finish and Analyze",
  }
};

const App: React.FC = () => {
  const [state, setState] = useState<AppState>('landing');
  const [mode, setMode] = useState<DiscoveryMode | null>(null);
  const [lang, setLang] = useState<Language>('zh');
  const [messages, setMessages] = useState<Message[]>([]);
  const [input, setInput] = useState('');
  const [isLoading, setIsLoading] = useState(false);
  const [result, setResult] = useState<DiscoveryResult | null>(null);
  const [questionCount, setQuestionCount] = useState(0);
  const [canFinishEarly, setCanFinishEarly] = useState(false);

  const scrollRef = useRef<HTMLDivElement>(null);
  const t = i18n[lang];

  useEffect(() => {
    if (scrollRef.current) {
      scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
    }
  }, [messages, isLoading]);

  const toggleLanguage = () => setLang(prev => prev === 'zh' ? 'en' : 'zh');

  const selectMode = (m: DiscoveryMode) => {
    setMode(m);
    setState('chatting');
    startJourney(m);
  };

  const startJourney = async (m: DiscoveryMode) => {
    setIsLoading(true);
    const initialMessage: Message = { id: 'start', role: 'user', content: 'START', timestamp: Date.now() };
    const firstQuestion = await getNextQuestion([initialMessage], m);
    setMessages([{ 
      id: Date.now().toString(), 
      role: 'assistant', 
      content: firstQuestion, 
      timestamp: Date.now() 
    }]);
    setQuestionCount(1);
    setIsLoading(false);
  };

  const handleSend = async () => {
    if (!input.trim() || isLoading || !mode) return;

    const userMessage: Message = {
      id: Date.now().toString(),
      role: 'user',
      content: input,
      timestamp: Date.now()
    };

    setMessages(prev => [...prev, userMessage]);
    setInput('');
    setIsLoading(true);

    try {
      const nextQRaw = await getNextQuestion([...messages, userMessage], mode);

      // 检查 AI 是否通过标记指示可以结束
      if (nextQRaw.includes('[DONE]') || questionCount >= MAX_QUESTIONS) {
        setCanFinishEarly(true);
      }

      const nextQ = nextQRaw.replace('[DONE]', '').trim();
      const assistantMessage: Message = {
        id: (Date.now() + 1).toString(),
        role: 'assistant',
        content: nextQ,
        timestamp: Date.now()
      };
      setMessages(prev => [...prev, assistantMessage]);
      setQuestionCount(prev => prev + 1);
    } catch (error) {
      console.error(error);
    } finally {
      setIsLoading(false);
    }
  };

  const analyze = async () => {
    if (!mode) return;
    setState('analyzing');
    setIsLoading(true);
    try {
      const finalResult = await generateFinalAnalysis(messages, mode);
      setResult(finalResult);
      setState('result');
    } catch (e) {
      console.error(e);
      setState('chatting');
    } finally {
      setIsLoading(false);
    }
  };

  const reset = () => {
    setState('landing');
    setMessages([]);
    setQuestionCount(0);
    setResult(null);
    setMode(null);
    setCanFinishEarly(false);
  };

  const parseBilingual = (text: string) => {
    const parts = text.split('[SEP]');
    if (parts.length < 2) return text;
    return (lang === 'zh' ? parts[0] : parts[1]).trim();
  };

  const getThemeColor = () => {
    if (mode === 'LIFE_MEANING') return 'indigo';
    if (mode === 'CAREER') return 'blue';
    if (mode === 'TALENT') return 'teal';
    return 'indigo';
  };

  if (state === 'landing') {
    return (
      <div className="min-h-screen flex flex-col items-center justify-center p-6 bg-gradient-to-br from-slate-50 to-indigo-50 relative overflow-hidden">
        <div className="absolute top-[-10%] left-[-10%] w-[40%] h-[40%] bg-indigo-200/20 rounded-full blur-[100px] animate-pulse"></div>
        <button onClick={toggleLanguage} className="absolute top-8 right-8 px-4 py-2 bg-white rounded-full shadow-sm hover:shadow-md transition-all text-xs font-bold text-indigo-600 border border-indigo-100">
          <Languages size={14} className="inline mr-2" /> {t.langToggle}
        </button>

        <div className="max-w-4xl w-full text-center space-y-12 z-10">
          <div className="space-y-4">
            <h1 className="text-6xl font-serif font-bold text-slate-900 tracking-tight">{t.title}</h1>
            <h2 className="text-2xl font-serif text-indigo-600/80">{t.subtitle}</h2>
            <p className="text-xl text-slate-500 leading-relaxed max-w-xl mx-auto">{t.landingDesc}</p>
          </div>

          <div className="grid md:grid-cols-3 gap-6 mt-12">
            {[
              { id: 'LIFE_MEANING', icon: ScrollText, label: t.modeLife, desc: t.modeLifeDesc, color: 'bg-indigo-50 text-indigo-600' },
              { id: 'CAREER', icon: Briefcase, label: t.modeCareer, desc: t.modeCareerDesc, color: 'bg-blue-50 text-blue-600' },
              { id: 'TALENT', icon: Heart, label: t.modeTalent, desc: t.modeTalentDesc, color: 'bg-teal-50 text-teal-600' },
            ].map((m) => (
              <button
                key={m.id}
                onClick={() => selectMode(m.id as DiscoveryMode)}
                className="group p-8 bg-white rounded-[2rem] border-2 border-transparent hover:border-indigo-100 hover:shadow-2xl hover:shadow-indigo-100/50 transition-all text-left space-y-4"
              >
                <div className={`w-14 h-14 ${m.color} rounded-2xl flex items-center justify-center group-hover:scale-110 transition-transform`}>
                  <m.icon size={28} />
                </div>
                <div>
                  <h3 className="text-xl font-bold text-slate-800">{m.label}</h3>
                  <p className="text-slate-400 text-sm mt-1">{m.desc}</p>
                </div>
              </button>
            ))}
          </div>
        </div>
      </div>
    );
  }

  if (state === 'analyzing') {
    return (
      <div className="min-h-screen flex flex-col items-center justify-center p-6 bg-slate-50">
        <div className="text-center space-y-8 max-w-md">
          <Sparkles size={64} className="text-indigo-500 mx-auto animate-pulse" />
          <h2 className="text-3xl font-serif font-bold text-slate-900">{t.analyzingTitle}</h2>
          <p className="text-slate-500 italic">"{t.analyzingDesc}"</p>
          <div className="w-full bg-slate-200 h-2 rounded-full overflow-hidden">
            <div className="bg-indigo-500 h-full w-full animate-[progress_3s_infinite]"></div>
          </div>
        </div>
        <style>{`@keyframes progress { 0% { width: 0%; } 100% { width: 100%; } }`}</style>
      </div>
    );
  }

  if (state === 'result' && result) {
    return (
      <div className="min-h-screen bg-white py-12 px-4 md:px-8">
        <div className="max-w-4xl mx-auto space-y-16">
          <div className="text-center space-y-6">
            <span className="text-indigo-600 font-bold tracking-widest uppercase text-sm">{t.resultTitle}</span>
            <h1 className="text-5xl md:text-6xl font-serif font-bold text-slate-900">{parseBilingual(result.title)}</h1>
          </div>

          <div className="grid md:grid-cols-2 gap-12">
            <div className="space-y-12">
              <section className="space-y-4">
                <div className="flex items-center gap-2 text-indigo-600 font-bold">
                  <Lightbulb size={20} /> 核心综述
                </div>
                <p className="text-xl text-slate-600 leading-relaxed font-serif italic border-l-4 border-indigo-100 pl-6">
                  {parseBilingual(result.summary)}
                </p>
              </section>

              <section className="space-y-6">
                <div className="flex items-center gap-2 text-teal-600 font-bold">
                  <Navigation size={20} /> 建议路径
                </div>
                <div className="space-y-4">
                  {result.suggestedPaths.map((p, i) => (
                    <div key={i} className="p-5 bg-slate-50 rounded-2xl border border-slate-100 hover:border-teal-200 transition-colors">
                      <p className="text-slate-700 font-medium">{parseBilingual(p)}</p>
                    </div>
                  ))}
                </div>
              </section>
            </div>

            <div className="space-y-12">
              <section className="space-y-6">
                <div className="flex items-center gap-2 text-blue-600 font-bold">
                  <Quote size={20} /> 关键洞见
                </div>
                <div className="space-y-4">
                  {result.keyInsights.map((ins, i) => (
                    <div key={i} className="flex gap-4 items-start">
                      <div className="w-6 h-6 rounded-full bg-blue-100 text-blue-600 flex-shrink-0 flex items-center justify-center text-xs font-bold">{i+1}</div>
                      <p className="text-slate-600 leading-relaxed">{parseBilingual(ins)}</p>
                    </div>
                  ))}
                </div>
              </section>

              <div className="p-10 bg-indigo-600 rounded-[3rem] text-white text-center space-y-4 shadow-2xl shadow-indigo-200">
                <p className="text-[10px] tracking-widest opacity-60 uppercase">Personal Mantra</p>
                <h3 className="text-2xl font-serif italic font-bold">"{parseBilingual(result.motto)}"</h3>
              </div>
            </div>
          </div>

          <div className="flex justify-center pt-8">
            <button onClick={reset} className="flex items-center gap-3 px-8 py-4 bg-slate-900 text-white rounded-2xl font-bold hover:bg-slate-800 transition-all">
              <RefreshCw size={18} /> {t.restart}
            </button>
          </div>
        </div>
      </div>
    );
  }

  const theme = getThemeColor();

  return (
    <div className={`flex flex-col h-screen bg-slate-50`}>
      <header className="px-6 py-4 flex items-center justify-between border-b bg-white/50 backdrop-blur-md sticky top-0 z-20">
        <div className="flex items-center gap-3">
          <button onClick={reset} className={`p-2 bg-${theme}-600 rounded-xl text-white`}>
            <Compass size={20} />
          </button>
          <div>
            <h1 className="font-bold text-slate-900 text-sm md:text-base">{t.title}</h1>
            <p className="text-[10px] text-slate-400 uppercase tracking-wider">{mode?.replace('_', ' ')}</p>
          </div>
        </div>
        <div className="flex items-center gap-4">
          <ProgressBar current={questionCount} total={MAX_QUESTIONS} />
          <button onClick={reset} className="p-2 text-slate-300 hover:text-red-500 transition-colors"><RefreshCw size={18} /></button>
        </div>
      </header>

      <main ref={scrollRef} className="flex-1 overflow-y-auto py-8">
        <div className="max-w-3xl mx-auto px-4 space-y-2">
          {messages.map((m) => <ChatBubble key={m.id} message={m} language={lang} />)}
          {isLoading && (
            <div className="flex gap-1 p-6">
              <div className="w-1.5 h-1.5 bg-indigo-300 rounded-full animate-bounce"></div>
              <div className="w-1.5 h-1.5 bg-indigo-300 rounded-full animate-bounce delay-150"></div>
              <div className="w-1.5 h-1.5 bg-indigo-300 rounded-full animate-bounce delay-300"></div>
            </div>
          )}
        </div>
      </main>

      <footer className="p-4 md:p-8 bg-white border-t">
        <div className="max-w-3xl mx-auto flex flex-col gap-4">
          <div className="relative">
            <textarea
              value={input}
              onChange={(e) => setInput(e.target.value)}
              onKeyDown={(e) => { if(e.key === 'Enter' && !e.shiftKey) { e.preventDefault(); handleSend(); } }}
              placeholder={t.inputPlaceholder}
              rows={2}
              className="w-full pl-6 pr-16 py-4 bg-slate-50 rounded-2xl border border-slate-100 focus:ring-2 focus:ring-indigo-500/20 focus:border-indigo-500 transition-all resize-none text-lg"
            />
            <button 
              onClick={handleSend}
              disabled={!input.trim() || isLoading}
              className="absolute right-3 bottom-3 p-3 bg-indigo-600 text-white rounded-xl hover:bg-indigo-700 disabled:bg-slate-100 disabled:text-slate-300"
            >
              <Send size={20} />
            </button>
          </div>
          {canFinishEarly && (
            <button 
              onClick={analyze}
              className="w-full py-4 bg-indigo-50 text-indigo-600 rounded-2xl font-bold flex items-center justify-center gap-2 hover:bg-indigo-100 transition-all"
            >
              <Sparkles size={18} /> {t.finishBtn}
            </button>
          )}
        </div>
      </footer>
    </div>
  );
};

