import { GoogleGenAI, Type } from "@google/genai";
import { Message, DiscoveryResult, DiscoveryMode } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

const getSystemInstruction = (mode: DiscoveryMode) => {
  let modeDesc = "";
  if (mode === 'LIFE_MEANING') {
    modeDesc = "专注于生命存在的终极意义。请从以下5个视角随机选择一个作为开场：1. 遗嘱视角（生命最后一天）；2. 永生困境（时间无限的虚无）；3. 经验机器（真实痛苦与虚假快乐）；4. 宇宙尺度（微观与宏观的对比）；5. 价值天平（牺牲与获得的抉择）。";
  } else if (mode === 'CAREER') {
    modeDesc = "专注于事业与社会价值。请随机选择：1. 创业者的风险孤独；2. 雇员的安全栅栏；3. 权力与责任的平衡点；4. 纯粹兴趣与商业变现的冲突；5. 职场生态中的自我异化。";
  } else {
    modeDesc = "专注于潜能、艺术与心流。请随机选择：1. 儿童时期的好奇心残余；2. 沉浸式创作的快感；3. 身体与感官的共鸣（体育/音乐）；4. 文字与表达的欲望；5. 解决复杂逻辑问题的快感。";
  }

  return `你是一位充满诗意、洞察力且语气坚定的哲学引导者。

当前模式：${modeDesc}

核心指令：
1. **排版要求**：在提问中，务必使用 Markdown 的 **双星号粗体** 对关键的哲学概念、两难选择或核心词汇进行强调。中文部分必须使用“黑体”风格的语气。
2. **强制双语**：[中文] [SEP] [English]。
3. **语言隔离**：中文部分绝对不准出现英文，英文部分不准出现中文。
4. **对话节奏**：
   - 每次只提一个问题。
   - 目标是在第 7 到 8 轮左右完成核心建模。
   - 当你觉得信息足够（通常在 6 轮之后），请在回复末尾添加标记 [DONE]。强制在 12 轮前结束。
5. **苏格拉底追问**：不要简单的列举，要通过解构用户的上一个回答来发起更有力的挑战。

示例：
“如果你必须在**不朽的孤独**与**平凡的喧嚣**中选择其一，你会将你的灵魂安置在何处？ [SEP] If you had to choose between **immortal solitude** and **ordinary clamor**, where would you anchor your soul?”`;
};

export const getNextQuestion = async (history: Message[], mode: DiscoveryMode): Promise<string> => {
  const contents = history.map(m => ({
    role: m.role === 'assistant' ? 'model' : 'user',
    parts: [{ text: m.content }]
  }));

  const response = await ai.models.generateContent({
    model: 'gemini-3-pro-preview',
    contents: contents as any,
    config: {
      systemInstruction: getSystemInstruction(mode),
      temperature: 0.85,
    },
  });

  return response.text || "你想继续深入吗？ [SEP] Shall we dive deeper?";
};

export const generateFinalAnalysis = async (history: Message[], mode: DiscoveryMode): Promise<DiscoveryResult> => {
  const conversation = history.map(m => `${m.role.toUpperCase()}: ${m.content}`).join('\n');

  const prompt = `你是一位世界级的心理学家和文学家。请基于以下关于“${mode}”的深度对话，为用户写一份极具【诗意】、【全面】且【震撼人心】的人生探索总结。

对话记录：
${conversation}

要求：
1. title: 必须是一个如同文学名著般的标题。
2. summary: 篇幅要长一点（150字左右中文），用优美的散文体描述用户的精神底色。
3. keyInsights: 3-5条，要一针见血，指出用户潜意识里的渴望与恐惧。
4. suggestedPaths: 3条具体的、可执行的方向，但措辞要高雅且专业。
5. motto: 一句足以刻在墓碑或纹在手臂上的强力信条。

所有内容必须严格遵循 [中文] [SEP] [English] 格式，且中文严禁混入英文单词。`;

  const response = await ai.models.generateContent({
    model: 'gemini-3-pro-preview',
    contents: [{ parts: [{ text: prompt }] }],
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          title: { type: Type.STRING },
          summary: { type: Type.STRING },
          keyInsights: { type: Type.ARRAY, items: { type: Type.STRING } },
          suggestedPaths: { type: Type.ARRAY, items: { type: Type.STRING } },
          motto: { type: Type.STRING }
        },
        required: ["title", "summary", "keyInsights", "suggestedPaths", "motto"]
      }
    }
  });

  return JSON.parse(response.text || "{}");
};

import React from 'react';
import { Message, Language } from '../types';

interface ChatBubbleProps {
  message: Message;
  language: Language;
}

export const ChatBubble: React.FC<ChatBubbleProps> = ({ message, language }) => {
  const isAssistant = message.role === 'assistant';

  const renderFormattedText = (text: string) => {
    // 简单的 Markdown 粗体转换 (**text** -> <b>text</b>)
    const parts = text.split(/(\*\*.*?\*\*)/g);
    return parts.map((part, i) => {
      if (part.startsWith('**') && part.endsWith('**')) {
        return <strong key={i}>{part.slice(2, -2)}</strong>;
      }
      return part;
    });
  };

  const getDisplayContent = (text: string) => {
    if (!isAssistant) return text;

    let parts = text.split('[SEP]');
    if (parts.length < 2) {
      parts = text.split(' / ');
    }

    if (parts.length < 2) return text;

    const content = language === 'zh' ? parts[0] : parts[1];
    return content.trim();
  };

  const displayContent = getDisplayContent(message.content);

  return (
    <div className={`flex w-full mb-8 ${isAssistant ? 'justify-start' : 'justify-end'}`}>
      <div 
        className={`max-w-[90%] md:max-w-[75%] px-8 py-5 rounded-[2rem] shadow-sm transition-all duration-500 hover:shadow-md ${
          isAssistant 
            ? 'bg-white text-gray-800 border border-indigo-50/50 rounded-tl-none font-heiti' 
            : 'bg-indigo-600 text-white rounded-tr-none'
        }`}
      >
        <div className={`text-lg md:text-xl leading-relaxed tracking-wide ${isAssistant ? 'italic' : ''}`}>
          {renderFormattedText(displayContent)}
        </div>
        <div className={`mt-3 flex items-center gap-2 opacity-40 text-[10px] ${isAssistant ? 'text-gray-400' : 'text-indigo-200'}`}>
          <span>{new Date(message.timestamp).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })}</span>
          {isAssistant && <div className="w-1 h-1 rounded-full bg-indigo-300" />}
        </div>
      </div>
    </div>
  );
};

