    langToggle: "切换至中文",
    finishBtn: "Generate Soul Map Report",
    backBtn: "Back to Home",
  }
};

const App: React.FC = () => {
  const [state, setState] = useState<AppState>('landing');
  const [mode, setMode] = useState<DiscoveryMode | null>(null);
  const [lang, setLang] = useState<Language>('zh');
  const [messages, setMessages] = useState<Message[]>([]);
  const [input, setInput] = useState('');
  const [isLoading, setIsLoading] = useState(false);
  const [result, setResult] = useState<DiscoveryResult | null>(null);
  const [questionCount, setQuestionCount] = useState(0);
  const [canFinishEarly, setCanFinishEarly] = useState(false);

  const scrollRef = useRef<HTMLDivElement>(null);
  const t = i18n[lang];

  useEffect(() => {
    if (scrollRef.current) {
      scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
    }
  }, [messages, isLoading]);

  const toggleLanguage = () => setLang(prev => prev === 'zh' ? 'en' : 'zh');

  const selectMode = (m: DiscoveryMode) => {
    setMode(m);
    setState('chatting');
    startJourney(m);
  };

  const startJourney = async (m: DiscoveryMode) => {
    setIsLoading(true);
    const initialMessage: Message = { id: 'start', role: 'user', content: 'START', timestamp: Date.now() };
    const firstQuestion = await getNextQuestion([initialMessage], m);
    setMessages([{ 
      id: Date.now().toString(), 
      role: 'assistant', 
      content: firstQuestion, 
      timestamp: Date.now() 
    }]);
    setQuestionCount(1);
    setIsLoading(false);
  };

  const handleSend = async () => {
    if (!input.trim() || isLoading || !mode) return;

    const userMessage: Message = {
      id: Date.now().toString(),
      role: 'user',
      content: input,
      timestamp: Date.now()
    };

    setMessages(prev => [...prev, userMessage]);
    setInput('');
    setIsLoading(true);

    try {
      const nextQRaw = await getNextQuestion([...messages, userMessage], mode);

      // 当超过7题或AI指示结束时，允许生成报告
      if (nextQRaw.includes('[DONE]') || questionCount >= TARGET_QUESTIONS) {
        setCanFinishEarly(true);
      }

      const nextQ = nextQRaw.replace('[DONE]', '').trim();
      const assistantMessage: Message = {
        id: (Date.now() + 1).toString(),
        role: 'assistant',
        content: nextQ,
        timestamp: Date.now()
      };
      setMessages(prev => [...prev, assistantMessage]);
      setQuestionCount(prev => prev + 1);

      // 如果达到强制最大数，直接引导总结
      if (questionCount >= MAX_QUESTIONS) {
        setCanFinishEarly(true);
      }
    } catch (error) {
      console.error(error);
    } finally {
      setIsLoading(false);
    }
  };

  const analyze = async () => {
    if (!mode) return;
    setState('analyzing');
    setIsLoading(true);
    try {
      const finalResult = await generateFinalAnalysis(messages, mode);
      setResult(finalResult);
      setState('result');
    } catch (e) {
      console.error(e);
      setState('chatting');
    } finally {
      setIsLoading(false);
    }
  };

  const reset = () => {
    setState('landing');
    setMessages([]);
    setQuestionCount(0);
    setResult(null);
    setMode(null);
    setCanFinishEarly(false);
  };

  const parseBilingual = (text: string) => {
    const parts = text.split('[SEP]');
    if (parts.length < 2) return text;
    return (lang === 'zh' ? parts[0] : parts[1]).trim();
  };

  if (state === 'landing') {
    return (
      <div className="min-h-screen flex flex-col items-center justify-center p-6 bg-slate-50 relative overflow-hidden">
        <div className="absolute top-[-20%] left-[-10%] w-[60%] h-[60%] bg-indigo-100/50 rounded-full blur-[120px]"></div>
        <button onClick={toggleLanguage} className="absolute top-8 right-8 px-5 py-2.5 bg-white/80 backdrop-blur rounded-full shadow-sm hover:shadow-md transition-all text-xs font-bold text-indigo-600 border border-indigo-50">
          <Languages size={14} className="inline mr-2" /> {t.langToggle}
        </button>

        <div className="max-w-4xl w-full text-center space-y-12 z-10">
          <div className="space-y-6">
            <h1 className="text-6xl md:text-7xl font-serif font-bold text-slate-900 tracking-tight">{t.title}</h1>
            <h2 className="text-xl md:text-2xl font-heiti text-indigo-500 uppercase tracking-widest">{t.subtitle}</h2>
            <p className="text-lg md:text-xl text-slate-500 leading-relaxed max-w-2xl mx-auto font-heiti">{t.landingDesc}</p>
          </div>

          <div className="grid md:grid-cols-3 gap-8 mt-16">
            {[
              { id: 'LIFE_MEANING', icon: ScrollText, label: t.modeLife, desc: t.modeLifeDesc, color: 'text-indigo-600 bg-indigo-50' },
              { id: 'CAREER', icon: Briefcase, label: t.modeCareer, desc: t.modeCareerDesc, color: 'text-blue-600 bg-blue-50' },
              { id: 'TALENT', icon: Heart, label: t.modeTalent, desc: t.modeTalentDesc, color: 'text-teal-600 bg-teal-50' },
            ].map((m) => (
              <button
                key={m.id}
                onClick={() => selectMode(m.id as DiscoveryMode)}
                className="group p-10 bg-white rounded-[3rem] border border-transparent hover:border-indigo-100 hover:shadow-2xl transition-all text-left space-y-5"
              >
                <div className={`w-16 h-16 ${m.color} rounded-2xl flex items-center justify-center group-hover:rotate-12 transition-transform`}>
                  <m.icon size={32} />
                </div>
                <div>
                  <h3 className="text-2xl font-bold text-slate-800 font-heiti">{m.label}</h3>
                  <p className="text-slate-400 text-sm mt-2 font-heiti leading-relaxed">{m.desc}</p>
                </div>
              </button>
            ))}
          </div>
        </div>
      </div>
    );
  }

  if (state === 'analyzing') {
    return (
      <div className="min-h-screen flex flex-col items-center justify-center p-6 bg-indigo-900 text-white">
        <div className="text-center space-y-10 max-w-lg">
          <div className="relative inline-block">
            <div className="absolute inset-0 bg-white/20 rounded-full blur-3xl animate-pulse"></div>
            <Sparkles size={80} className="relative animate-spin-slow" />
          </div>
          <div className="space-y-4">
            <h2 className="text-4xl font-serif font-bold">{t.analyzingTitle}</h2>
            <p className="text-indigo-200 text-lg italic font-serif opacity-80">{t.analyzingDesc}</p>
          </div>
          <div className="w-full bg-white/10 h-1 rounded-full overflow-hidden">
            <div className="bg-white h-full w-full animate-[loading_4s_infinite]"></div>
          </div>
        </div>
        <style>{`
          @keyframes loading { 0% { transform: translateX(-100%); } 100% { transform: translateX(100%); } }
          @keyframes spin-slow { from { transform: rotate(0deg); } to { transform: rotate(360deg); } }
          .animate-spin-slow { animation: spin-slow 10s linear infinite; }
        `}</style>
      </div>
    );
  }

  if (state === 'result' && result) {
    return (
      <div className="min-h-screen bg-white py-20 px-6 md:px-12">
        <div className="max-w-5xl mx-auto space-y-24">
          <div className="text-center space-y-8">
            <div className="inline-flex items-center gap-3 px-6 py-2 bg-indigo-50 text-indigo-600 rounded-full text-xs font-bold uppercase tracking-[0.2em]">
              <Sparkles size={14} /> {t.resultTitle}
            </div>
            <h1 className="text-6xl md:text-7xl font-serif font-bold text-slate-900 leading-[1.1]">
              {parseBilingual(result.title)}
            </h1>
          </div>

          <div className="grid lg:grid-cols-12 gap-16 items-start">
            <div className="lg:col-span-7 space-y-16">
              <section className="space-y-6">
                <div className="flex items-center gap-3 text-indigo-600 text-sm font-bold uppercase tracking-widest">
                  <Lightbulb size={20} /> 精神底色概述
                </div>
                <div className="text-2xl md:text-3xl text-slate-700 leading-snug font-serif italic border-l-8 border-indigo-600/10 pl-10 py-2">
                  {parseBilingual(result.summary)}
                </div>
              </section>

              <section className="space-y-10">
                <div className="flex items-center gap-3 text-teal-600 text-sm font-bold uppercase tracking-widest">
                  <Navigation size={20} /> 未来行动建议
                </div>
                <div className="grid gap-6">
                  {result.suggestedPaths.map((p, i) => (
                    <div key={i} className="group p-8 bg-slate-50 rounded-[2.5rem] border border-slate-100 hover:bg-white hover:shadow-xl transition-all">
                      <p className="text-xl text-slate-800 font-heiti leading-relaxed">{parseBilingual(p)}</p>
                    </div>
                  ))}
                </div>
              </section>
            </div>

            <div className="lg:col-span-5 space-y-16">
              <section className="space-y-8">
                <div className="flex items-center gap-3 text-blue-600 text-sm font-bold uppercase tracking-widest">
                  <Quote size={20} /> 深度洞见
                </div>
                <div className="space-y-8">
                  {result.keyInsights.map((ins, i) => (
                    <div key={i} className="flex gap-6 items-start group">
                      <span className="text-4xl font-serif text-blue-200 group-hover:text-blue-400 transition-colors">0{i+1}</span>
                      <p className="text-lg text-slate-600 leading-relaxed font-heiti pt-2">{parseBilingual(ins)}</p>
                    </div>
                  ))}
                </div>
              </section>

              <div className="relative group">
                <div className="absolute -inset-4 bg-indigo-100 rounded-[4rem] blur-2xl opacity-40 group-hover:opacity-70 transition-opacity"></div>
