                  <p className="text-xs tracking-[0.3em] opacity-60 uppercase font-bold">Soul Mantra</p>
                  <h3 className="text-3xl md:text-4xl font-serif italic font-bold leading-relaxed">
                    "{parseBilingual(result.motto)}"
                  </h3>
                </div>
              </div>

              <div className="flex flex-col gap-4">
                <button onClick={reset} className="w-full py-5 bg-slate-900 text-white rounded-2xl font-bold hover:bg-black transition-all shadow-xl shadow-slate-200 flex items-center justify-center gap-3">
                  <RefreshCw size={20} /> {t.restart}
                </button>
              </div>
            </div>
          </div>
        </div>
      </div>
    );
  }

  return (
