          <button onClick={() => { if(confirm(t.backBtn)) reset() }} className="p-3 bg-indigo-600 rounded-2xl text-white shadow-lg shadow-indigo-100">
            <Compass size={24} />
          </button>
          <div>
            <h1 className="font-serif font-bold text-slate-900 text-lg">{t.title}</h1>
            <div className="flex items-center gap-2">
              <span className="w-1.5 h-1.5 rounded-full bg-green-500 animate-pulse"></span>
              <p className="text-[10px] text-slate-400 uppercase tracking-widest font-bold">{mode?.replace('_', ' ')}</p>
            </div>
          </div>
        </div>
        <div className="flex items-center gap-6">
          <div className="hidden md:block w-32">
            <ProgressBar current={questionCount} total={TARGET_QUESTIONS} />
          </div>
          <span className="text-xs font-mono font-bold text-indigo-600 bg-indigo-50 px-3 py-1.5 rounded-full">
            {questionCount}
          </span>
          <button onClick={toggleLanguage} className="p-2 text-slate-400 hover:text-indigo-600 transition-colors">
            <Languages size={20} />
          </button>
        </div>
      </header>

