                rows={2}
                className="flex-1 pl-8 pr-16 py-5 bg-white rounded-2xl border border-slate-100 focus:outline-none focus:ring-2 focus:ring-indigo-500/20 text-xl font-heiti transition-all resize-none shadow-sm"
              />
              <button 
                onClick={handleSend}
                disabled={!input.trim() || isLoading}
                className="absolute right-4 bottom-4 p-4 bg-indigo-600 text-white rounded-xl hover:bg-indigo-700 disabled:bg-slate-100 disabled:text-slate-300 shadow-xl shadow-indigo-100 transition-all active:scale-95"
              >
                <Send size={24} />
              </button>
            </div>
          </div>
          {canFinishEarly && (
            <button 
              onClick={analyze}
              className="w-full py-5 bg-indigo-50 text-indigo-700 rounded-2xl font-bold flex items-center justify-center gap-3 hover:bg-indigo-600 hover:text-white transition-all shadow-md group"
            >
              <Sparkles size={20} className="group-hover:rotate-12 transition-transform" /> 
              <span className="font-heiti tracking-widest">{t.finishBtn}</span>
            </button>
          )}
        </div>
      </footer>
    </div>
  );
};

