export const getNextQuestion = async (history: Message[], mode: DiscoveryMode): Promise<string> => {
  const contents = history.map(m => ({
    role: m.role === 'assistant' ? 'model' : 'user',
    parts: [{ text: m.content }]
  }));

  const response = await ai.models.generateContent({
    model: 'gemini-3-pro-preview',
    contents: contents as any,
    config: {
      systemInstruction: getSystemInstruction(mode),
      temperature: 0.85,
    },
  });

  return response.text || "你想继续深入吗？ [SEP] Shall we dive deeper?";
};

export const generateFinalAnalysis = async (history: Message[], mode: DiscoveryMode): Promise<DiscoveryResult> => {
  const conversation = history.map(m => `${m.role.toUpperCase()}: ${m.content}`).join('\n');

  const prompt = `你是一位世界级的心理学家、哲学家和文学家。请基于以下关于“${mode}”的深度对话，为用户撰写一份极具【诗意】、【全面】且【触及灵魂】的人生探索报告。

对话记录：
${conversation}

JSON 字段要求：
1. title: 一个如同经典文学名著或史诗电影般的标题。
2. summary: 篇幅约 150-200 字，以极具文学美感的散文体描述用户的精神图景。
3. keyInsights: 4 条关于其潜意识价值取向、潜在才华或核心执着的深度洞察。
4. suggestedPaths: 3 条既具有实际操作性又符合其精神气质的未来行动建议。
5. motto: 一句短小有力、足以作为人生指南的信条。

所有内容必须遵循 [中文内容] [SEP] [English Content] 格式，且中文严禁混入英文。`;

  const response = await ai.models.generateContent({
    model: 'gemini-3-pro-preview',
    contents: [{ parts: [{ text: prompt }] }],
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          title: { type: Type.STRING },
          summary: { type: Type.STRING },
          keyInsights: { type: Type.ARRAY, items: { type: Type.STRING } },
          suggestedPaths: { type: Type.ARRAY, items: { type: Type.STRING } },
          motto: { type: Type.STRING }
        },
        required: ["title", "summary", "keyInsights", "suggestedPaths", "motto"]
      }
    }
  });

  return JSON.parse(response.text || "{}");
};

