      scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
    }
  }, [messages, isLoading]);

  const toggleLanguage = () => setLang(prev => prev === 'zh' ? 'en' : 'zh');

  const selectMode = (m: DiscoveryMode) => {
    setMode(m);
    setState('chatting');
    startJourney(m);
  };

  const startJourney = async (m: DiscoveryMode) => {
    setIsLoading(true);
    const initialMessage: Message = { id: 'start', role: 'user', content: 'START', timestamp: Date.now() };
    const firstQuestion = await getNextQuestion([initialMessage], m);
    setMessages([{ 
      id: Date.now().toString(), 
      role: 'assistant', 
      content: firstQuestion, 
      timestamp: Date.now() 
    }]);
    setQuestionCount(1);
    setIsLoading(false);
  };

  const handleSend = async () => {
    if (!input.trim() || isLoading || !mode) return;

    const userMessage: Message = {
      id: Date.now().toString(),
      role: 'user',
      content: input,
      timestamp: Date.now()
    };

    setMessages(prev => [...prev, userMessage]);
    setInput('');
    setIsLoading(true);

    try {
      const nextQRaw = await getNextQuestion([...messages, userMessage], mode);
      if (nextQRaw.includes('[DONE]') || questionCount >= TARGET_QUESTIONS) {
        setCanFinishEarly(true);
      }
      const nextQ = nextQRaw.replace('[DONE]', '').trim();
      const assistantMessage: Message = {
        id: (Date.now() + 1).toString(),
        role: 'assistant',
        content: nextQ,
        timestamp: Date.now()
      };
      setMessages(prev => [...prev, assistantMessage]);
      setQuestionCount(prev => prev + 1);
      if (questionCount >= MAX_QUESTIONS) setCanFinishEarly(true);
    } catch (error) {
      console.error(error);
    } finally {
      setIsLoading(false);
    }
  };

  const analyze = async () => {
    if (!mode) return;
    setState('analyzing');
    setIsLoading(true);
    try {
      const finalResult = await generateFinalAnalysis(messages, mode);
      setResult(finalResult);
      setState('result');
    } catch (e) {
      console.error(e);
      setState('chatting');
    } finally {
      setIsLoading(false);
    }
  };

  const reset = () => {
    setState('landing');
    setMessages([]);
    setQuestionCount(0);
    setResult(null);
    setMode(null);
    setCanFinishEarly(false);
  };

  const exportAsImage = async (ref: React.RefObject<HTMLDivElement>, filename: string) => {
    if (!ref.current) return;
    try {
      const canvas = await html2canvas(ref.current, {
        useCORS: true,
        backgroundColor: '#ffffff',
        scale: 2, // higher resolution
      });
      const link = document.createElement('a');
      link.download = `${filename}.png`;
