  const saveSettings = (newSettings: AppSettings) => {
    setSettings(newSettings);
    localStorage.setItem('explorer_compass_settings', JSON.stringify(newSettings));
    setShowSettings(false);
  };

  const reset = () => {
    setState('landing');
    setMode(null);
    setIntensity('QUICK');
    setMessages([]);
    setInput('');
    setIsLoading(false);
    setError(null);
    setResult(null);
    setQuestionCount(0);
    setCanFinishEarly(false);
