              {id:'CAREER', icon:Briefcase, label:t.modeCareer, desc:t.modeCareerDesc, color:'bg-blue-50 text-blue-600'},
              {id:'TALENT', icon:Heart, label:t.modeTalent, desc:t.modeTalentDesc, color:'bg-teal-50 text-teal-600'}
