              <h1 className="text-5xl md:text-7xl font-serif font-bold text-slate-900 leading-[1.15]">{parseBilingual(result.title)}</h1>
              <div className="w-24 h-1.5 bg-gradient-to-r from-indigo-500 to-blue-500 mx-auto rounded-full shadow-lg shadow-indigo-100"></div>
            </div>

            <div className="w-full max-w-3xl py-10 text-center space-y-12 relative z-10">
              <div className="text-indigo-400 font-black tracking-[0.4em] text-[10px] uppercase">剖析 / Essence</div>
              <p className="text-2xl md:text-4xl text-slate-700 leading-[1.8] font-serif italic italic px-10 border-l-4 border-indigo-500/10">"{parseBilingual(result.summary)}"</p>
