async function callDeepSeek(apiKey: string, systemInstruction: string, messages: any[], responseJson: boolean = false): Promise<string> {
  const response = await fetch('https://api.deepseek.com/v1/chat/completions', {
    method: 'POST',
    headers: {
      'Content-Type': 'application/json',
      'Authorization': `Bearer ${apiKey}`
    },
    body: JSON.stringify({
      model: 'deepseek-reasoner',
      messages: [
        { role: 'system', content: systemInstruction },
        ...messages
      ],
      response_format: responseJson ? { type: 'json_object' } : undefined
    })
  });

  if (!response.ok) {
    const error = await response.json();
    throw new Error(error.error?.message || 'DeepSeek API Error');
  }

  const data = await response.json();
  return data.choices[0].message.content;
}

export const getNextQuestion = async (history: Message[], mode: DiscoveryMode, intensity: DiscoveryIntensity, settings: AppSettings): Promise<string> => {
  return callWithRetry(async () => {
    const turnCount = Math.floor(history.length / 2) + 1;
    const systemInstruction = getSystemInstruction(mode, intensity, turnCount);
    const useKey = settings.apiKey || process.env.API_KEY || "";

    if (settings.provider === 'deepseek') {
      const msgs = history.map(m => ({
        role: m.role === 'assistant' ? 'assistant' : 'user',
        content: m.content
      }));
      return await callDeepSeek(useKey, systemInstruction, msgs);
    } else {
      const ai = new GoogleGenAI({ apiKey: useKey });
      const contents = history.map(m => ({
        role: m.role === 'assistant' ? 'model' : 'user',
        parts: [{ text: m.content }]
      }));
      const response = await ai.models.generateContent({
        model: 'gemini-3-pro-preview',
        contents: contents as any,
        config: {
          systemInstruction,
          temperature: 0.8,
        },
      });
      return response.text || "请继续。 [SEP] Please continue.";
    }
  });
};

export const generateFinalAnalysis = async (history: Message[], mode: DiscoveryMode, settings: AppSettings): Promise<DiscoveryResult> => {
  return callWithRetry(async () => {
    const conversation = history.map(m => `${m.role.toUpperCase()}: ${m.content}`).join('\n');

    const modeConfigs = {
      LIFE_MEANING: {
        template: `
          1. 标题：揭示其“人生意义底色”。（例如：‘西绪福斯的快乐舞步’或‘斯多葛式的宁静孤岛’）
          2. 深度剖析：必须明确判定用户主要属于 9 大思潮中的哪一类，并分析这种逻辑如何支撑或束缚了他的生活。
          3. 核心洞察：指出用户在追求意义过程中的“盲区”。
          4. 进化建议：针对其所属流派，给出一个极具启发性的生活实验（如：禅宗派建议去‘练习无目的的步行’，荒诞派建议去‘在重复的劳作中歌唱’）。
          5. 维度：【意志自由度 (Autonomy)】、【超越性链接 (Connection)】、【内在平和度 (Serenity)】、【潜能实现度 (Growth)】、【真相承受力 (Truth Endurance)】。
        `,
        persona: "跨领域哲学分析大师"
      },
      JUSTICE: {
        template: `
          1. 标题：关于“正义”的灵魂裁决。
          2. 维度：【功利效用倾向 (Utility)】、【道德绝对主义 (Absolutism)】、【个体权利保护 (Rights)】、【社会公平正义 (Equity)】、【伦理选择勇气 (Courage)】。
        `,
        persona: "正义审判官"
      },
      TALENT: {
        template: `
          1. 标题：天赋能量图谱。
          2. 维度：【心流进入度】、【感官敏锐力】、【创造性潜能】、【能量自供力】、【技能变现率】。
        `,
        persona: "天赋挖掘师"
      }
    };

    const current = modeConfigs[mode];

    const prompt = `你是一位世界级的灵魂图谱分析师。请扮演【${current.persona}】，根据对话撰写报告。

    模板要求：
    ${current.template}

    对话记录：
    ${conversation}

    输出要求：
    1. 必须使用 JSON 格式。
    2. 文字部分必须双语 [中文] [SEP] [English]。
    3. JSON 结构必须严格包含：title, summary, keyInsights (array), suggestedPaths (array), motto, dimensions (array of {label, value})。`;

    const useKey = settings.apiKey || process.env.API_KEY || "";

    if (settings.provider === 'deepseek') {
      const resultStr = await callDeepSeek(useKey, "Ethical & Philosophical Logic Engine", [{ role: 'user', content: prompt }], true);
      return JSON.parse(resultStr);
    } else {
      const ai = new GoogleGenAI({ apiKey: useKey });
      const response = await ai.models.generateContent({
        model: 'gemini-3-pro-preview',
        contents: [{ parts: [{ text: prompt }] }],
        config: {
          responseMimeType: "application/json",
          responseSchema: {
            type: Type.OBJECT,
            properties: {
              title: { type: Type.STRING },
              summary: { type: Type.STRING },
              keyInsights: { type: Type.ARRAY, items: { type: Type.STRING } },
              suggestedPaths: { type: Type.ARRAY, items: { type: Type.STRING } },
              motto: { type: Type.STRING },
              dimensions: {
                type: Type.ARRAY,
                items: {
                  type: Type.OBJECT,
                  properties: { label: { type: Type.STRING }, value: { type: Type.NUMBER } },
                  required: ["label", "value"]
                }
              }
            },
            required: ["title", "summary", "keyInsights", "suggestedPaths", "motto", "dimensions"]
          }
        }
      });
      return JSON.parse(response.text || "{}");
    }
  });
};

